391	func (t *Tunnel) Reload(cfg *config.Config) error {
392		t.reloadMu.Lock()
393		defer t.reloadMu.Unlock()
394	
395		for _, w := range reloadWarnings(t.cfg, cfg) {
396			t.log.Warn("reload: ignored config change (path-membership reload only)", "change", w)
397		}
398	
399		// Rebind the /metrics endpoint if its listen address changed (T23). This is one of
400		// the few non-path fields a reload DOES apply: the endpoint is external to the WG
401		// session and the Bind, so restarting it disturbs neither. applyMetricsLocked reuses
402		// the tunnel's stable Source (its derived-throughput state survives), and on a refuse
403		// (e.g. a newly non-loopback address) leaves the previous endpoint running and fails
404		// the reload — the running tunnel is never disturbed. Applied BEFORE the path diff so
405		// a metrics-refuse aborts before any membership change.
406		if cfg.Metrics.Listen != t.metricsListen {
407			if err := t.applyMetricsLocked(cfg.Metrics.Listen); err != nil {
408				return fmt.Errorf("device: reload metrics endpoint: %w", err)
409			}
410			t.log.Info("reload: metrics endpoint rebound", "listen", cfg.Metrics.Listen)
411		}
412	
413		add, remove := diffPaths(t.bind.PathNames(), cfg.Paths)
414		for _, def := range add {
415			if err := t.bind.AddPath(def); err != nil {
416				return fmt.Errorf("device: reload add path %q: %w", def.Name, err)
417			}
418			t.log.Info("reload: path added", "path", def.Name)
419		}
420		for _, name := range remove {
421			if err := t.bind.RemovePath(name); err != nil {
422				return fmt.Errorf("device: reload remove path %q: %w", name, err)
423			}
424			t.log.Info("reload: path removed", "path", name)
425		}
426		// Advance the running config to the membership now in service. Survivors keep their
427		// ORIGINAL parameters and all non-path fields stay as booted (the ignored changes
428		// were not applied), so a subsequent identical reload re-warns about a still-diverged
429		// file rather than silently accepting it. Metrics.Listen is carried to the applied
430		// value so a subsequent reload diffs against the endpoint actually running.
431		t.cfg = runningConfig(t.cfg, add, remove)
432		t.cfg.Metrics.Listen = t.metricsListen
433		return nil
434	}
435	
436	// reloadWarnings compares the desired config against the currently-running one and
437	// returns one human-readable warning per change a path-membership-only reload (T30)
438	// cannot apply: a modified same-name path (source/dest), a path reorder, and any
439	// non-path field. Membership add/remove is NOT reported here — it is applied. Full
440	// modify-support is out of scope; SILENCE is not — the operator must be told what was
441	// ignored. It is a pure function so the warning set is unit-testable.
442	func reloadWarnings(live, desired *config.Config) []string {
443		var w []string
444	
445		if live.Role != desired.Role {
446			w = append(w, fmt.Sprintf("role %q -> %q", live.Role, desired.Role))
447		}
448		if !reflect.DeepEqual(live.PSK, desired.PSK) {
449			w = append(w, "psk changed")
450		}

